"""Context commands for GreenNode AgentBase CLI.

Shows supported request/context headers and SDK decorators.
"""

import click
from rich.console import Console
from rich.table import Table

from . import CONTEXT_SETTINGS
from ..runtime.models import (
    ACCESS_TOKEN_HEADER,
    AUTHORIZATION_HEADER,
    CUSTOM_HEADER_PREFIX,
    OAUTH2_CALLBACK_URL_HEADER,
    REQUEST_ID_HEADER,
    SESSION_HEADER,
    USER_ID_HEADER,
)

console = Console()

# Single source of truth: header name, description, context getter
HEADERS_INFO = [
    (REQUEST_ID_HEADER, "Request correlation ID (or generated UUID if omitted).", "get_request_id()"),
    (SESSION_HEADER, "Session identifier for grouping requests.", "get_session_id()"),
    (ACCESS_TOKEN_HEADER, "Agent identity (workload) access token for auth.", "get_workload_access_token()"),
    (USER_ID_HEADER, "User identifier (or config fallback).", "get_user_id()"),
    (OAUTH2_CALLBACK_URL_HEADER, "OAuth2 callback URL for delegation flows.", "get_oauth2_callback_url()"),
    (AUTHORIZATION_HEADER, "Forwarded Authorization header from the client.", "get_request_headers()"),
    (f"{CUSTOM_HEADER_PREFIX}*", "Any custom header with this prefix is available in context.", "get_request_headers()"),
]

DECORATORS_INFO = [
    (
        "entrypoint",
        "Registers the main handler and drives AgentBase context extraction from request headers.",
        "GreenNodeAgentBaseApp.entrypoint",
    ),
    (
        "requires_api_key",
        "Secret interceptor: fetches an API key before the handler and injects it into a parameter. Manages scope of keys. Supports M2M (static) and USER_FEDERATION (delegation).",
        "identity.requires_api_key",
    ),
    (
        "requires_access_token",
        "Secret interceptor: fetches an OAuth2 access token before the handler and injects it into a parameter. Manages scope of tokens. Supports M2M and USER_FEDERATION.",
        "identity.requires_access_token",
    ),
]


@click.group(name="context", context_settings=CONTEXT_SETTINGS)
def context_group() -> None:
    """Show AgentBase context headers and decorators.

    Use 'headers' to list supported request headers and their context getters.
    Use 'decorators' to see SDK decorators (entrypoint, requires_api_key, requires_access_token).
    """
    pass


@context_group.command(name="headers")
def headers_cmd() -> None:
    """List all supported request/context headers and their descriptions.

    These headers are read by the runtime and exposed via GreenNodeAgentBaseContext.
    """
    table = Table(title="Supported context headers", show_header=True, header_style="bold")
    table.add_column("Header", style="cyan")
    table.add_column("Description", style="white")
    table.add_column("Context getter", style="green")
    for name, desc, getter in HEADERS_INFO:
        table.add_row(name, desc, getter)
    console.print(table)


@context_group.command(name="decorators")
def decorators_cmd() -> None:
    """Describe SDK decorators: entrypoint, requires_api_key, requires_access_token.

    Covers server declaration, AgentBase context extraction, and secret interceptors
    (M2M and USER_FEDERATION).
    """
    table = Table(title="SDK decorators", show_header=True, header_style="bold")
    table.add_column("Decorator", style="cyan")
    table.add_column("Description", style="white")
    table.add_column("Module", style="green")
    for name, desc, module in DECORATORS_INFO:
        table.add_row(name, desc, module)
    console.print(table)
    console.print("\n[bold]Auth flows:[/bold] M2M (machine-to-machine static credentials), USER_FEDERATION (delegation with callback URL).\n")
